```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::optional<std::string> city;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

struct MutualFriendsResult {
  std::string user1_name;
  std::string user2_name;
  int mutual_friend_count;
};

struct FriendOfFriendResult {
  std::string user1_name;
  std::string user2_name;
  std::string mutual_friend_name;
};

struct NetworkStats {
  int user_id;
  std::string username;
  int friend_count;
  double avg_friend_count;
  bool above_average;
};

struct Recommendation {
  std::string user1_name;
  std::string user2_name;
  std::string city;
};

std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen::literals;

  // Create database connection
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create tables
  conn | sqlgen::create_table<User> | sqlgen::if_not_exists;
  conn | sqlgen::create_table<Friendship> | sqlgen::if_not_exists;

  // Insert data
  conn | sqlgen::insert(users);
  conn | sqlgen::insert(friendships);

  // Query 1: Mutual friends using self-join and subquery
  auto mutual_friends_query = sqlgen::select_from<User, "u1">(
      "username"_c.as<"user1_name">,
      "username"_c.as<"user2_name">
    )
    .inner_join<Friendship, "f1">("user_id"_c == "user_id1"_c)
    .inner_join<User, "f2_user">("user_id2"_c == "user_id"_c)
    .inner_join<User, "u2">("user_id"_c == "user_id"_c)
    .where("u1"_c < "u2"_c)
    .where(sqlgen::exists(
        sqlgen::select_from<Friendship, "f3">("user_id1"_c, "user_id2"_c)
        .where("user_id1"_c == "u1"_c && "user_id2"_c == "u2"_c)
    ))
    .group_by("u1"_c, "u2"_c)
    .having("friend_count"_c > 0)
    .to<std::vector<FriendConnection>>();

  // Query 2: Users with more than N friends using nested query
  auto friend_count_query = sqlgen::select_from<User, "u">(
      "user_id"_c,
      "username"_c,
      sqlgen::count("user_id2"_c).as<"friend_count">
    )
    .left_join<Friendship, "f">("user_id"_c == "user_id1"_c)
    .group_by("user_id"_c, "username"_c)
    .having("friend_count"_c > (
        sqlgen::select_from<Friendship, "f2">()
        .group_by("user_id1"_c)
        .avg(sqlgen::count("user_id2"_c)).as<"avg_friend_count">)
    )
    .order_by("friend_count"_c.desc())
    .to<std::vector<NetworkStats>>();

  // Query 3: Friend-of-friend relationships
  auto friend_of_friend_query = sqlgen::select_from<User, "u1">(
      "username"_c.as<"user1_name">,
      "username"_c.as<"user2_name">,
      "username"_c.as<"mutual_friend_name">
    )
    .inner_join<Friendship, "f1">("user_id"_c == "user_id1"_c)
    .inner_join<Friendship, "f2">("user_id2"_c == "user_id1"_c)
    .inner_join<User, "u2">("user_id2"_c == "user_id"_c)
    .where(sqlgen::count_distinct("user_id2"_c) == 1)
    .to<std::vector<FriendOfFriendResult>>();

  // Query 4: Count friends per user
  auto friend_stats_query = sqlgen::select_from<User, "u">(
      "user_id"_c,
      "username"_c,
      sqlgen::count("user_id2"_c).as<"friend_count">
    )
    .left_join<Friendship, "f">("user_id"_c == "user_id1"_c)
    .group_by("user_id"_c, "username"_c)
    .to<std::vector<NetworkStats>>();

  // Query 5: Same city recommendations
  auto recommendation_query = sqlgen::select_from<User, "u1">(
      "username"_c.as<"user1_name">,
      "username"_c.as<"user2_name">,
      "city"_c
    )
    .inner_join<User, "u2">("city"_c == "city"_c && "user_id"_c < "user_id"_c)
    .where(sqlgen::not_exists(
        sqlgen::select_from<Friendship, "f">("user_id1"_c, "user_id2"_c)
        .where(("user_id1"_c == "u1"_c && "user_id2"_c == "u2"_c) || 
               ("user_id1"_c == "u2"_c && "user_id2"_c == "u1"_c))
    ))
    .to<std::vector<Recommendation>>();

  // Execute all queries
  auto mutual_results = mutual_friends_query(conn);
  auto friend_count_results = friend_count_query(conn);
  auto friend_of_friend_results = friend_of_friend_query(conn);
  auto friend_stats_results = friend_stats_query(conn);
  auto recommendation_results = recommendation_query(conn);

  // Combine results (for demonstration, returning mutual friends)
  std::vector<FriendConnection> final_results;
  for (const auto& result : mutual_results) {
    final_results.push_back(result);
  }

  return final_results;
}

}  // namespace analyze_social_network
```

